; Stack Manipulation Techniques in x86-64 Assembly\n\nsection .text\n\nglobal _start\n\n_start:\n    ; Example of pushing values onto the stack\n    mov rax, 10      ; Move 10 into rax\n    push rax         ; Push rax onto the stack\n    mov rax, 20      ; Move 20 into rax\n    push rax         ; Push rax onto the stack\n\n    ; Example of popping values from the stack\n    pop rbx          ; Pop the top value (20) into rbx\n    pop rdx          ; Pop the next value (10) into rdx\n\n    ; Use values (Just for demonstration purposes; normally there would be other instructions)\n    ; ...\n\n    ; Exit the program\n    mov rax, 60      ; syscall: exit\n    xor rdi, rdi     ; exit code 0\n    syscall\n